from enum import Enum, auto
from dataclasses import dataclass
from typing import List, Tuple


class State(Enum):
    MAIN_GREEN = auto()
    MAIN_YELLOW = auto()
    SIDE_GREEN = auto()
    SIDE_YELLOW = auto()
    PED_WALK = auto()
    PED_CLEAR = auto()
    ALL_RED = auto()
    EMERGENCY = auto()


@dataclass(frozen=True)
class Outputs:
    main: str
    side: str
    walk: str


DURATIONS: dict = {
    State.MAIN_GREEN: 30,
    State.MAIN_YELLOW: 5,
    State.SIDE_GREEN: 20,
    State.SIDE_YELLOW: 5,
    State.PED_WALK: 15,
    State.PED_CLEAR: 5,
    State.ALL_RED: 2,
    State.EMERGENCY: 1,
}

OUTPUT_MAP: dict = {
    State.MAIN_GREEN:  Outputs("green", "red", "stop"),
    State.MAIN_YELLOW: Outputs("yellow", "red", "stop"),
    State.SIDE_GREEN:  Outputs("red", "green", "stop"),
    State.SIDE_YELLOW: Outputs("red", "yellow", "stop"),
    State.PED_WALK:    Outputs("red", "red", "walk"),
    State.PED_CLEAR:   Outputs("red", "red", "flash"),
    State.ALL_RED:     Outputs("red", "red", "stop"),
    State.EMERGENCY:   Outputs("red", "red", "stop"),
}


class TrafficFSM:
    """Moore machine traffic light controller."""

    def __init__(self) -> None:
        self._state = State.MAIN_GREEN
        self._timer: int = DURATIONS[State.MAIN_GREEN]
        self._ped_request: bool = False
        self._history: List[Tuple[State, Outputs]] = []

    def _get_outputs(self) -> Outputs:
        return OUTPUT_MAP[self._state]

    def _transition(self, next_state: State) -> None:
        self._state = next_state
        self._timer = DURATIONS[next_state]

    def tick(
        self,
        side_sensor: bool = False,
        ped_button: bool = False,
        emergency: bool = False,
    ) -> Outputs:
        # Emergency override
        if emergency:
            if self._state != State.EMERGENCY:
                self._transition(State.EMERGENCY)
            outputs = self._get_outputs()
            self._history.append((self._state, outputs))
            return outputs

        # Return from emergency
        if self._state == State.EMERGENCY and not emergency:
            self._transition(State.MAIN_GREEN)
            self._ped_request = False

        # Latch pedestrian request (persists until served)
        if ped_button:
            self._ped_request = True

        # Decrement timer
        self._timer -= 1

        # State transitions when timer expires
        if self._timer <= 0:
            if self._state == State.MAIN_GREEN:
                if side_sensor or self._ped_request:
                    self._transition(State.MAIN_YELLOW)
                else:
                    self._timer = DURATIONS[State.MAIN_GREEN]
            elif self._state == State.MAIN_YELLOW:
                if self._ped_request:
                    self._transition(State.PED_WALK)
                    self._ped_request = False
                else:
                    self._transition(State.SIDE_GREEN)
            elif self._state == State.SIDE_GREEN:
                self._transition(State.SIDE_YELLOW)
            elif self._state == State.SIDE_YELLOW:
                self._transition(State.ALL_RED)
            elif self._state == State.PED_WALK:
                self._transition(State.PED_CLEAR)
            elif self._state == State.PED_CLEAR:
                self._transition(State.ALL_RED)
            elif self._state == State.ALL_RED:
                self._transition(State.MAIN_GREEN)

        outputs = self._get_outputs()
        self._history.append((self._state, outputs))
        return outputs

    @property
    def current_state(self) -> State:
        return self._state

    @property
    def history(self) -> List[Tuple[State, Outputs]]:
        return self._history

from typing import List


class SIPORegister:
    """Serial-In, Parallel-Out shift register."""

    def __init__(self, width: int) -> None:
        self._width = width
        self._register: int = 0
        self._mask: int = (1 << width) - 1
        self._bits_shifted: int = 0

    def shift_in(self, bit: int) -> None:
        """Shift a bit in from the MSB side. LSB is discarded."""
        # Shift right to make room, then OR the new bit at MSB position
        self._register = ((self._register >> 1) | ((bit & 1) << (self._width - 1))) & self._mask
        self._bits_shifted += 1

    def read_parallel(self) -> int:
        return self._register

    def is_full(self) -> bool:
        return self._bits_shifted >= self._width

    def reset(self) -> None:
        self._register = 0
        self._bits_shifted = 0


class PISORegister:
    """Parallel-In, Serial-Out shift register."""

    def __init__(self, width: int) -> None:
        self._width = width
        self._register: int = 0
        self._bits_remaining: int = 0

    def load(self, value: int) -> None:
        self._register = value & ((1 << self._width) - 1)
        self._bits_remaining = self._width

    def shift_out(self) -> int:
        lsb = self._register & 1
        self._register >>= 1
        if self._bits_remaining > 0:
            self._bits_remaining -= 1
        return lsb

    def is_empty(self) -> bool:
        return self._register == 0 and self._bits_remaining == 0
